1	package com.coding.assistant.config;
2	
3	import org.springframework.context.annotation.Bean;
4	import org.springframework.context.annotation.Configuration;
5	import org.springframework.data.redis.connection.RedisConnectionFactory;
6	import org.springframework.data.redis.core.RedisTemplate;
7	import org.springframework.data.redis.serializer.GenericJackson2JsonRedisSerializer;
8	import org.springframework.data.redis.serializer.StringRedisSerializer;
9	
10	@Configuration
11	public class RedisConfig {
12	
13	    @Bean
14	    public RedisTemplate<String, Object> redisTemplate(RedisConnectionFactory factory) {
15	        RedisTemplate<String, Object> template = new RedisTemplate<>();
16	        template.setConnectionFactory(factory);
17	
18	        StringRedisSerializer keySerializer = new StringRedisSerializer();
19	        GenericJackson2JsonRedisSerializer valueSerializer = new GenericJackson2JsonRedisSerializer();
20	
21	        template.setKeySerializer(keySerializer);
22	        template.setHashKeySerializer(keySerializer);
23	        template.setValueSerializer(valueSerializer);
24	        template.setHashValueSerializer(valueSerializer);
25	
26	        template.afterPropertiesSet();
27	        return template;
28	    }
29	}
